<span class="line">  <span class="token keyword">rpc</span> <span class="token function">UploadFile</span><span class="token punctuation">(</span><span class="token keyword">stream</span> <span class="token class-name">FileRequest</span><span class="token punctuation">)</span> <span class="token keyword">returns</span> <span class="token punctuation">(</span><span class="token class-name">UploadResponse</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
